"""
install_calendar_context.py
Run from C:\\vantro:    python install_calendar_context.py

Writes the new /api/installer/calendar-context endpoint.
This is a read-only aggregator that returns:
  - User schedule (default or override)
  - Holiday balance (entitlement / used / remaining)
  - All time-off entries
  - Public holidays
  - Anonymised team time-off counts per day

Idempotent. Safe to re-run.
"""
import base64, os, sys

CONTENT_B64 = ""

TARGET = os.path.join("app", "api", "installer", "calendar-context", "route.ts")


def main():
    cwd = os.getcwd()
    if not cwd.lower().endswith("vantro"):
        print(f"WARNING: cwd is {cwd}")
        print("Run from C:\\vantro. Continue? (y/n)")
        if input().strip().lower() != "y":
            sys.exit(1)

    full = os.path.join(cwd, TARGET)
    os.makedirs(os.path.dirname(full), exist_ok=True)

    contents = base64.b64decode(CONTENT_B64).decode("utf-8")
    with open(full, "w", encoding="utf-8", newline="\n") as f:
        f.write(contents)
    print(f"  wrote: {TARGET}  ({len(contents)} bytes)")
    print()
    print("Done.")
    print()
    print("Next:  npm run build, commit, push.")


if __name__ == "__main__":
    main()
